mapper.select:
SELECT ARTIFACT_ID, PROJECT_ID, ARTIFACT_TYPE, FILE_NAME, FILE_PATH, GENERATED_BY, GENERATED_AT FROM ARTIFACT_HISTORY
AND PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
AND ARTIFACT_TYPE = #{artifactType}
ORDER BY GENERATED_AT DESC

SELECT
    ISSUE_KEY,
    ISSUE_TYPE,
    TITLE,
    STATUS,
    PRIORITY,
    START_DATE,
    DUE_DATE,
    RESOLVED_DATE,
    ESTIMATED_MINUTES,
    SPENT_MINUTES
FROM ISSUE
WHERE PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
  AND (
        CAST(CREATED_AT AS DATE) BETWEEN #{startDate} AND #{endDate}
        OR CAST(COALESCE(UPDATED_AT, CREATED_AT) AS DATE) BETWEEN #{startDate} AND #{endDate}
        OR START_DATE BETWEEN #{startDate} AND #{endDate}
        OR DUE_DATE BETWEEN #{startDate} AND #{endDate}
        OR RESOLVED_DATE BETWEEN #{startDate} AND #{endDate}
  )
ORDER BY PRIORITY ASC, DUE_DATE ASC NULLS LAST, CREATED_AT DESC

SELECT TE.TEST_EVIDENCE_ID, TE.PROJECT_ID, P.PROJECT_CODE, P.PROJECT_NAME, TE.ISSUE_ID, I.ISSUE_KEY, I.TITLE AS ISSUE_TITLE, TE.TEST_NAME, TE.TEST_TARGET, TE.TEST_PROCEDURE, TE.EXPECTED_RESULT, TE.ACTUAL_RESULT, TE.RESULT_STATUS, COALESCE(U.DISPLAY_NAME, U.USERNAME) AS TESTER_NAME, TE.TESTED_AT, TE.SCREENSHOT_FILE_NAME, TE.SCREENSHOT_FILE_PATH FROM TEST_EVIDENCE TE INNER JOIN PROJECT P ON TE.PROJECT_ID = P.PROJECT_ID INNER JOIN ISSUE I ON TE.ISSUE_ID = I.ISSUE_ID INNER JOIN APP_USER U ON TE.TESTER_ID = U.USER_ID
AND TE.PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler} AND CAST(TE.TESTED_AT AS DATE) BETWEEN #{startDate} AND #{endDate}
AND TE.ISSUE_ID = #{issueId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
AND TE.RESULT_STATUS = #{resultStatus}
ORDER BY TE.TESTED_AT ASC, I.ISSUE_KEY ASC, TE.TEST_NAME ASC
